{
  "name": "SIPEKA Kesbangpol NTB",
  "description": "Sistem Informasi Perizinan Penelitian Kesbangpol Provinsi NTB. Aplikasi untuk pengajuan izin penelitian dan dashboard monitoring data perizinan periode 2023-2026.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum PermitStatus {
  PENDING = 'PENDING',
  APPROVED = 'APPROVED',
  REJECTED = 'REJECTED'
}

export interface ResearchPermit {
  id: string;
  applicantName: string;
  idNumber: string;
  university: string;
  researchTitle: string;
  researchLocation: string; // Kabupaten/Kota di NTB
  duration: string;
  category: string;
  submissionDate: string;
  status: PermitStatus;
  year: number;
}

export interface DashboardStats {
  total: number;
  approved: number;
  pending: number;
  rejected: number;
}

export interface YearlyData {
  year: number;
  count: number;
}

export interface LocationData {
  name: string;
  value: number;
}

import { ResearchPermit, PermitStatus } from './types';

export const NTB_REGENCIES = [
  'Kota Mataram',
  'Lombok Barat',
  'Lombok Tengah',
  'Lombok Timur',
  'Lombok Utara',
  'Sumbawa',
  'Sumbawa Barat',
  'Dompu',
  'Bima',
  'Kota Bima'
];

export const RESEARCH_CATEGORIES = [
  'Sosial & Budaya',
  'Pendidikan',
  'Ekonomi & Bisnis',
  'Kesehatan',
  'Teknologi Informasi',
  'Lingkungan Hidup',
  'Hukum & Politik'
];

// Mock data for 2023 - 2026
const generateMockData = (): ResearchPermit[] => {
  const data: ResearchPermit[] = [];
  const years = [2023, 2024, 2025, 2026];
  const firstNames = ['Budi', 'Siti', 'Agus', 'Lalu', 'Baiq', 'Dewi', 'Rian', 'Putri', 'Hendra', 'Eka'];
  const lastNames = ['Pratama', 'Sari', 'Wahyudi', 'Hidayat', 'Saputra', 'Lestari', 'Kusuma', 'Ayu'];
  const unis = ['Universitas Mataram', 'UIN Mataram', 'Universitas Hamzanwadi', 'Universitas Teknologi Sumbawa', 'Universitas Muhammadiyah Mataram'];

  let idCounter = 1;

  years.forEach(year => {
    const count = year === 2026 ? 150 : Math.floor(Math.random() * 200) + 100;
    for (let i = 0; i < count; i++) {
      const fName = firstNames[Math.floor(Math.random() * firstNames.length)];
      const lName = lastNames[Math.floor(Math.random() * lastNames.length)];
      data.push({
        id: `PERMIT-${year}-${idCounter++}`,
        applicantName: `${fName} ${lName}`,
        idNumber: `520${Math.floor(Math.random() * 900000000000)}`,
        university: unis[Math.floor(Math.random() * unis.length)],
        researchTitle: `Analisis Dampak ${RESEARCH_CATEGORIES[Math.floor(Math.random() * RESEARCH_CATEGORIES.length)]} di NTB`,
        researchLocation: NTB_REGENCIES[Math.floor(Math.random() * NTB_REGENCIES.length)],
        duration: '3 Bulan',
        category: RESEARCH_CATEGORIES[Math.floor(Math.random() * RESEARCH_CATEGORIES.length)],
        submissionDate: `${year}-${Math.floor(Math.random() * 12) + 1}-${Math.floor(Math.random() * 28) + 1}`,
        status: year < 2025 ? PermitStatus.APPROVED : (Math.random() > 0.3 ? PermitStatus.APPROVED : PermitStatus.PENDING),
        year: year
      });
    }
  });
  return data;
};

export const MOCK_PERMITS = generateMockData();

import { GoogleGenAI } from "@google/genai";
import { ResearchPermit } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getResearchInsights = async (permits: ResearchPermit[]) => {
  if (!process.env.API_KEY) return "API Key belum dikonfigurasi.";

  const summary = permits.slice(0, 20).map(p => ({
    title: p.researchTitle,
    category: p.category,
    year: p.year
  }));

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Berdasarkan data sampel berikut dari Sistem Izin Penelitian Kesbangpol NTB (2023-2026), berikan ringkasan tren penelitian dalam 3 poin singkat menggunakan Bahasa Indonesia: ${JSON.stringify(summary)}`,
    });
    return response.text || "Gagal mendapatkan insight.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Error saat menganalisis data.";
  }
};

import React, { useMemo, useState, useEffect } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, 
  PieChart, Pie, Cell, LineChart, Line, Legend 
} from 'recharts';
import { MOCK_PERMITS, NTB_REGENCIES } from '../constants';
import { PermitStatus } from '../types';
import { getResearchInsights } from '../services/geminiService';

const COLORS = ['#10b981', '#3b82f6', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#06b6d4'];

const StatCard: React.FC<{ title: string; value: number | string; icon: React.ReactNode; color: string }> = ({ title, value, icon, color }) => (
  <div className={`bg-white p-6 rounded-2xl shadow-sm border-l-4 ${color} transition-all hover:shadow-md`}>
    <div className="flex justify-between items-center">
      <div>
        <p className="text-sm font-medium text-slate-500 uppercase tracking-wider">{title}</p>
        <h3 className="text-3xl font-bold mt-1 text-slate-800">{value}</h3>
      </div>
      <div className="p-3 bg-slate-50 rounded-xl text-slate-600">
        {icon}
      </div>
    </div>
  </div>
);

const Dashboard: React.FC = () => {
  const [insights, setInsights] = useState<string>("Sedang memuat analisis AI...");

  useEffect(() => {
    const fetchInsights = async () => {
      const result = await getResearchInsights(MOCK_PERMITS);
      setInsights(result);
    };
    fetchInsights();
  }, []);

  const yearlyStats = useMemo(() => {
    const years = [2023, 2024, 2025, 2026];
    return years.map(year => ({
      name: year.toString(),
      total: MOCK_PERMITS.filter(p => p.year === year).length,
      approved: MOCK_PERMITS.filter(p => p.year === year && p.status === PermitStatus.APPROVED).length
    }));
  }, []);

  const regencyStats = useMemo(() => {
    return NTB_REGENCIES.map(reg => ({
      name: reg,
      value: MOCK_PERMITS.filter(p => p.researchLocation === reg).length
    })).sort((a, b) => b.value - a.value);
  }, []);

  const totals = useMemo(() => ({
    total: MOCK_PERMITS.length,
    approved: MOCK_PERMITS.filter(p => p.status === PermitStatus.APPROVED).length,
    pending: MOCK_PERMITS.filter(p => p.status === PermitStatus.PENDING).length,
    rejected: MOCK_PERMITS.filter(p => p.status === PermitStatus.REJECTED).length,
  }), []);

  return (
    <div className="space-y-8 animate-fade-in">
      {/* Summary Section */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard 
          title="Total Permohonan" 
          value={totals.total} 
          color="border-blue-500" 
          icon={<svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"></path></svg>} 
        />
        <StatCard 
          title="Disetujui" 
          value={totals.approved} 
          color="border-emerald-500" 
          icon={<svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7"></path></svg>} 
        />
        <StatCard 
          title="Menunggu" 
          value={totals.pending} 
          color="border-amber-500" 
          icon={<svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>} 
        />
        <StatCard 
          title="Ditolak" 
          value={totals.rejected} 
          color="border-rose-500" 
          icon={<svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path></svg>} 
        />
      </div>

      {/* AI Insights Section */}
      <div className="bg-gradient-to-br from-indigo-500 to-purple-600 rounded-2xl p-6 text-white shadow-lg overflow-hidden relative">
        <div className="relative z-10">
          <div className="flex items-center gap-2 mb-2">
            <svg className="w-6 h-6 text-indigo-200" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 2a1 1 0 011 1v1a1 1 0 11-2 0V3a1 1 0 011-1zm4 8a4 4 0 11-8 0 4 4 0 018 0zm-.464 4.95l.707.707a1 1 0 001.414-1.414l-.707-.707a1 1 0 00-1.414 1.414zm2.12-10.607a1 1 0 010 1.414l-.706.707a1 1 0 11-1.414-1.414l.707-.707a1 1 0 011.414 0zM17 11a1 1 0 100-2h-1a1 1 0 100 2h1zm-7 4a1 1 0 011 1v1a1 1 0 11-2 0v-1a1 1 0 011-1zM5.05 6.464A1 1 0 106.465 5.05l-.708-.707a1 1 0 00-1.414 1.414l.707.707zm1.414 8.486l-.707.707a1 1 0 01-1.414-1.414l.707-.707a1 1 0 011.414 1.414zM4 11a1 1 0 100-2H3a1 1 0 000 2h1z" clipRule="evenodd"></path></svg>
            <h4 className="text-lg font-bold">AI Data Insight (Kesbangpol Analysis)</h4>
          </div>
          <div className="bg-white/10 backdrop-blur-md rounded-xl p-4 text-indigo-50 border border-white/20 whitespace-pre-wrap leading-relaxed">
            {insights}
          </div>
        </div>
        <div className="absolute top-0 right-0 w-64 h-64 bg-white/10 rounded-full blur-3xl -mr-32 -mt-32"></div>
      </div>

      {/* Charts Section */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Trend per Tahun */}
        <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-100">
          <h4 className="text-lg font-bold text-slate-800 mb-6">Tren Pengajuan Izin (2023 - 2026)</h4>
          <div className="h-[350px]">
            <ResponsiveContainer width="100%" height="100%">
              <LineChart data={yearlyStats}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} />
                <Tooltip 
                  contentStyle={{borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)'}}
                />
                <Legend iconType="circle" />
                <Line type="monotone" dataKey="total" name="Total Pengajuan" stroke="#3b82f6" strokeWidth={3} dot={{r: 6, fill: '#3b82f6'}} />
                <Line type="monotone" dataKey="approved" name="Izin Terbit" stroke="#10b981" strokeWidth={3} dot={{r: 6, fill: '#10b981'}} />
              </LineChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Distribusi Lokasi */}
        <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-100">
          <h4 className="text-lg font-bold text-slate-800 mb-6">Distribusi Lokasi Penelitian</h4>
          <div className="h-[350px]">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={regencyStats} layout="vertical">
                <CartesianGrid strokeDasharray="3 3" horizontal={false} stroke="#f1f5f9" />
                <XAxis type="number" hide />
                <YAxis dataKey="name" type="category" width={120} axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 11}} />
                <Tooltip cursor={{fill: 'transparent'}} contentStyle={{borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)'}} />
                <Bar dataKey="value" name="Jumlah" radius={[0, 6, 6, 0]}>
                  {regencyStats.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { NTB_REGENCIES, RESEARCH_CATEGORIES } from '../constants';

const ApplicationForm: React.FC = () => {
  const [submitted, setSubmitted] = useState(false);
  const [formData, setFormData] = useState({
    name: '',
    idNumber: '',
    email: '',
    phone: '',
    university: '',
    title: '',
    location: NTB_REGENCIES[0],
    category: RESEARCH_CATEGORIES[0],
    duration: '3 Bulan'
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setSubmitted(true);
    // Simulate API call
    setTimeout(() => {
      setSubmitted(false);
      alert("Permohonan berhasil dikirim! Silakan cek email Anda secara berkala untuk update status.");
      setFormData({
        name: '', idNumber: '', email: '', phone: '', university: '', 
        title: '', location: NTB_REGENCIES[0], category: RESEARCH_CATEGORIES[0], duration: '3 Bulan'
      });
    }, 1500);
  };

  return (
    <div className="max-w-4xl mx-auto bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden animate-slide-up">
      <div className="bg-indigo-600 p-8 text-white">
        <h2 className="text-2xl font-bold">Formulir Pengajuan Izin Penelitian</h2>
        <p className="text-indigo-100 mt-2">Lengkapi data di bawah ini untuk mengajukan permohonan rekomendasi penelitian di Provinsi NTB.</p>
      </div>

      <form onSubmit={handleSubmit} className="p-8 space-y-8">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {/* Personal Info */}
          <div className="space-y-4">
            <h3 className="text-lg font-semibold text-slate-800 border-b pb-2">Identitas Pemohon</h3>
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Nama Lengkap (Sesuai KTP)</label>
              <input 
                type="text" required
                value={formData.name}
                onChange={e => setFormData({...formData, name: e.target.value})}
                className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 focus:border-transparent outline-none transition-all"
                placeholder="Contoh: Ahmad Subarjo"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">NIK (Nomor Induk Kependudukan)</label>
              <input 
                type="text" required
                value={formData.idNumber}
                onChange={e => setFormData({...formData, idNumber: e.target.value})}
                className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 focus:border-transparent outline-none transition-all"
                placeholder="520xxxxxxxxxxxxx"
              />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Email</label>
                <input 
                  type="email" required
                  value={formData.email}
                  onChange={e => setFormData({...formData, email: e.target.value})}
                  className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 focus:border-transparent outline-none transition-all"
                  placeholder="name@email.com"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Nomor HP/WA</label>
                <input 
                  type="tel" required
                  value={formData.phone}
                  onChange={e => setFormData({...formData, phone: e.target.value})}
                  className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 focus:border-transparent outline-none transition-all"
                  placeholder="0812xxxxxx"
                />
              </div>
            </div>
          </div>

          {/* Research Info */}
          <div className="space-y-4">
            <h3 className="text-lg font-semibold text-slate-800 border-b pb-2">Data Penelitian</h3>
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Instansi / Universitas</label>
              <input 
                type="text" required
                value={formData.university}
                onChange={e => setFormData({...formData, university: e.target.value})}
                className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 focus:border-transparent outline-none transition-all"
                placeholder="Nama Kampus atau Lembaga"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Judul Penelitian</label>
              <textarea 
                required rows={3}
                value={formData.title}
                onChange={e => setFormData({...formData, title: e.target.value})}
                className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 focus:border-transparent outline-none transition-all"
                placeholder="Tuliskan judul lengkap penelitian Anda..."
              />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Lokasi Penelitian</label>
                <select 
                  value={formData.location}
                  onChange={e => setFormData({...formData, location: e.target.value})}
                  className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                >
                  {NTB_REGENCIES.map(r => <option key={r} value={r}>{r}</option>)}
                </select>
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Bidang Penelitian</label>
                <select 
                  value={formData.category}
                  onChange={e => setFormData({...formData, category: e.target.value})}
                  className="w-full px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                >
                  {RESEARCH_CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
                </select>
              </div>
            </div>
          </div>
        </div>

        <div className="pt-6">
          <button 
            type="submit" 
            disabled={submitted}
            className={`w-full py-4 rounded-xl font-bold text-lg shadow-lg transition-all transform active:scale-[0.98] ${submitted ? 'bg-slate-400 cursor-not-allowed' : 'bg-indigo-600 hover:bg-indigo-700 text-white hover:shadow-indigo-200'}`}
          >
            {submitted ? (
              <span className="flex items-center justify-center gap-2">
                <svg className="animate-spin h-5 w-5 text-white" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                Memproses...
              </span>
            ) : "Kirim Permohonan Izin"}
          </button>
        </div>
      </form>
    </div>
  );
};

export default ApplicationForm;

import React, { useState } from 'react';
import { MOCK_PERMITS } from '../constants';
import { PermitStatus } from '../types';

const ApplicationList: React.FC = () => {
  const [filter, setFilter] = useState('');
  const [yearFilter, setYearFilter] = useState('Semua');

  const filteredPermits = MOCK_PERMITS.filter(p => {
    const matchesSearch = p.applicantName.toLowerCase().includes(filter.toLowerCase()) || 
                         p.university.toLowerCase().includes(filter.toLowerCase()) ||
                         p.id.toLowerCase().includes(filter.toLowerCase());
    const matchesYear = yearFilter === 'Semua' || p.year.toString() === yearFilter;
    return matchesSearch && matchesYear;
  }).slice(0, 50); // Limit display for performance

  const getStatusBadge = (status: PermitStatus) => {
    switch(status) {
      case PermitStatus.APPROVED: return <span className="px-3 py-1 bg-emerald-100 text-emerald-700 rounded-full text-xs font-bold uppercase">Terbit</span>;
      case PermitStatus.PENDING: return <span className="px-3 py-1 bg-amber-100 text-amber-700 rounded-full text-xs font-bold uppercase">Menunggu</span>;
      case PermitStatus.REJECTED: return <span className="px-3 py-1 bg-rose-100 text-rose-700 rounded-full text-xs font-bold uppercase">Ditolak</span>;
    }
  };

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
      <div className="p-6 border-b border-slate-100 flex flex-col md:flex-row md:items-center justify-between gap-4">
        <h3 className="text-xl font-bold text-slate-800">Database Izin Penelitian</h3>
        <div className="flex flex-wrap items-center gap-3">
          <select 
            value={yearFilter}
            onChange={(e) => setYearFilter(e.target.value)}
            className="px-4 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
          >
            <option value="Semua">Semua Tahun</option>
            <option value="2023">2023</option>
            <option value="2024">2024</option>
            <option value="2025">2025</option>
            <option value="2026">2026</option>
          </select>
          <div className="relative">
            <input 
              type="text"
              placeholder="Cari nama / kampus / ID..."
              value={filter}
              onChange={(e) => setFilter(e.target.value)}
              className="pl-10 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm focus:ring-2 focus:ring-indigo-500 outline-none w-64"
            />
            <svg className="w-4 h-4 absolute left-3 top-2.5 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"></path></svg>
          </div>
        </div>
      </div>

      <div className="overflow-x-auto">
        <table className="w-full text-left">
          <thead className="bg-slate-50 border-b border-slate-100">
            <tr>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">ID Permohonan</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Pemohon</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Instansi</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Lokasi</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Status</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Tahun</th>
