                <td className="px-6 py-4">
                  <div className="text-sm font-bold text-slate-800">{permit.applicantName}</div>
                  <div className="text-xs text-slate-400">{permit.idNumber}</div>
                </td>
                <td className="px-6 py-4 text-sm text-slate-600">{permit.university}</td>
                <td className="px-6 py-4 text-sm text-slate-600">{permit.researchLocation}</td>
                <td className="px-6 py-4">{getStatusBadge(permit.status)}</td>
                <td className="px-6 py-4 text-sm font-semibold text-slate-700">{permit.year}</td>
