);

export default ApplicationForm;

import React, { useState } from 'react';
import { MOCK_PERMITS } from '../constants';
import { PermitStatus, ResearchPermit } from '../types';

const ApplicationList: React.FC = () => {
  const [permits, setPermits] = useState(MOCK_PERMITS);
  const [filter, setFilter] = useState('');
  const [selectedPermit, setSelectedPermit] = useState<ResearchPermit | null>(null);

  const handleStatusChange = (id: string, newStatus: PermitStatus) => {
    setPermits(prev => prev.map(p => p.id === id ? { ...p, status: newStatus } : p));
  };

  const filteredPermits = permits.filter(p => 
    p.applicantName.toLowerCase().includes(filter.toLowerCase()) || 
    p.university.toLowerCase().includes(filter.toLowerCase())
  ).slice(0, 20);

  const printPermit = (permit: ResearchPermit) => {
    setSelectedPermit(permit);
    setTimeout(() => window.print(), 500);
  };

  return (
    <div className="space-y-6">
      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <div className="p-6 border-b border-slate-100 flex items-center justify-between">
          <h3 className="text-xl font-bold text-slate-800">Manajemen Permohonan</h3>
          <input 
            type="text" 
            placeholder="Cari pemohon..." 
            value={filter}
            onChange={e => setFilter(e.target.value)}
            className="px-4 py-2 bg-slate-50 border border-slate-200 rounded-xl text-sm outline-none focus:ring-2 focus:ring-indigo-500 w-64"
          />
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-slate-50/50">
              <tr>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Pemohon & Kampus</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Judul Penelitian</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Status</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase text-center">Aksi Admin</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredPermits.map(permit => (
                <tr key={permit.id} className="hover:bg-slate-50/30">
                  <td className="px-6 py-4">
                    <div className="text-sm font-bold text-slate-800">{permit.applicantName}</div>
                    <div className="text-xs text-slate-500">{permit.university}</div>
                  </td>
                  <td className="px-6 py-4">
                    <p className="text-xs text-slate-600 line-clamp-2 max-w-xs">{permit.researchTitle}</p>
                  </td>
                  <td className="px-6 py-4">
                    <StatusBadge status={permit.status} />
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex items-center justify-center gap-2">
                      {permit.status === PermitStatus.PENDING ? (
                        <>
                          <button onClick={() => handleStatusChange(permit.id, PermitStatus.APPROVED)} className="p-2 bg-emerald-100 text-emerald-600 rounded-lg hover:bg-emerald-200 transition-colors" title="Setujui">
                            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7"></path></svg>
                          </button>
                          <button onClick={() => handleStatusChange(permit.id, PermitStatus.REJECTED)} className="p-2 bg-rose-100 text-rose-600 rounded-lg hover:bg-rose-200 transition-colors" title="Tolak">
                            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path></svg>
                          </button>
                        </>
                      ) : permit.status === PermitStatus.APPROVED ? (
                        <button onClick={() => printPermit(permit)} className="flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-xl text-xs font-bold hover:bg-indigo-700 transition-all">
                          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 002 2h2m2 4h6a2 2 0 002-2v-4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2zm8-12V5a2 2 0 00-2-2H9a2 2 0 00-2 2v4h10z"></path></svg>
                          Cetak Izin
                        </button>
                      ) : (
                        <span className="text-xs text-slate-400 font-medium italic">Permohonan Ditolak</span>
                      )}
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* Hidden Print Template */}
      {selectedPermit && <PrintTemplate permit={selectedPermit} />}
    </div>
  );
};

const StatusBadge: React.FC<{status: PermitStatus}> = ({ status }) => {
  const styles = {
    [PermitStatus.APPROVED]: "bg-emerald-100 text-emerald-700",
    [PermitStatus.PENDING]: "bg-amber-100 text-amber-700 animate-pulse",
    [PermitStatus.REJECTED]: "bg-rose-100 text-rose-700"
  };
  const labels = {
    [PermitStatus.APPROVED]: "Telah Terbit",
    [PermitStatus.PENDING]: "Verifikasi Admin",
    [PermitStatus.REJECTED]: "Ditolak"
  };
  return <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase ${styles[status]}`}>{labels[status]}</span>;
};

