        {icon}
      </div>
    </div>
  </div>
);

const QRCodeCard: React.FC<{ 
  title: string; 
  subtitle: string; 
  page: 'apply' | 'tracking'; 
  color: string;
  onActivate: (page: 'apply' | 'tracking') => void;
}> = ({ title, subtitle, page, color, onActivate }) => {
  const currentBaseUrl = window.location.origin + window.location.pathname;
  const qrUrl = `${currentBaseUrl}?page=${page}&mode=public`;
  const qrImageSource = `https://api.qrserver.com/v1/create-qr-code/?size=300x300&data=${encodeURIComponent(qrUrl)}`;

  return (
    <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 flex flex-col items-center text-center group hover:border-indigo-200 transition-all">
      <h5 className="text-lg font-black text-slate-800 tracking-tight mb-1">{title}</h5>
      <p className="text-slate-500 text-xs mb-6">{subtitle}</p>

      <div className={`p-4 rounded-[2rem] bg-slate-50 mb-6 group-hover:bg-white group-hover:shadow-xl transition-all border-4 ${color}`}>
        <img 
          src={qrImageSource} 
          alt={`QR Code for ${title}`} 
          className="w-48 h-48 mix-blend-multiply"
        />
      </div>

      <div className="flex flex-col gap-2 w-full">
        <button 
          onClick={() => onActivate(page)}
          className="text-[10px] font-black text-indigo-600 bg-indigo-50 py-2.5 rounded-xl border border-indigo-100 uppercase tracking-widest hover:bg-indigo-600 hover:text-white transition-all w-full"
        >
          Tes Link Publik
        </button>
        <p className="text-[9px] text-slate-400 font-bold italic">Tampilkan QR ini di loket pelayanan</p>
      </div>
    </div>
  );
};

interface DashboardProps {
  permits: ResearchPermit[];
  onSetPublicMode?: (val: boolean) => void;
  onSetActiveTab?: (tab: any) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ permits, onSetPublicMode, onSetActiveTab }) => {
  const yearlyStats = useMemo(() => {
    const years = [2023, 2024, 2025, 2026];
    return years.map(year => ({
      name: year.toString(),
      total: permits.filter(p => p.year === year).length,
      approved: permits.filter(p => p.year === year && p.status === PermitStatus.APPROVED).length
    }));
  }, [permits]);

  const categoryData = useMemo(() => {
    return RESEARCH_CATEGORIES.map((cat, index) => {
      const count = permits.filter(p => p.category === cat).length;
      const percentage = permits.length > 0 ? ((count / permits.length) * 100).toFixed(1) : "0";
      return {
        name: cat,
        value: count,
        percentage: percentage,
        color: COLORS[index % COLORS.length]
      };
    }).sort((a, b) => b.value - a.value);
  }, [permits]);

  const regencyStats = useMemo(() => {
    return NTB_REGENCIES.map(reg => ({
      name: reg,
      value: permits.filter(p => p.researchLocation === reg).length
    })).sort((a, b) => b.value - a.value);
  }, [permits]);

  const totals = useMemo(() => ({
    total: permits.length,
    approved: permits.filter(p => p.status === PermitStatus.APPROVED).length,
    pending: permits.filter(p => p.status === PermitStatus.PENDING).length,
    rejected: permits.filter(p => p.status === PermitStatus.REJECTED).length,
  }), [permits]);

  const handleActivatePublicMode = (page: 'apply' | 'tracking') => {
